
UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=bZpqmR5Xhvs',
  conteudo_texto = '<h2>Gestão Ambiental</h2><p>Sistema de Gestão Ambiental (SGA), ISO 14001 e licenciamento para concursos da Petrobras.</p><h3>📋 Sistema de Gestão Ambiental (SGA)</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Conjunto de políticas, práticas e procedimentos para <strong>gerenciar os impactos ambientais</strong> de uma organização.</p><h4>Objetivos:</h4><ul><li>Minimizar impactos negativos</li><li>Cumprir legislação ambiental</li><li>Melhorar desempenho ambiental continuamente</li><li>Reduzir custos com recursos e resíduos</li></ul></div><h3>🏆 ISO 14001</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><p>Norma internacional para <strong>Sistemas de Gestão Ambiental</strong>.</p><h4>Ciclo PDCA:</h4><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Etapa</th><th style=''padding:10px;border:1px solid #ddd;''>Ações</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Plan (Planejar)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Identificar aspectos ambientais, definir objetivos e metas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Do (Executar)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Implementar programas, treinar pessoas, comunicar</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Check (Verificar)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Monitorar, medir, auditar</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Act (Agir)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Corrigir não conformidades, melhorar continuamente</td></tr></table></div><h3>📝 Licenciamento Ambiental</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><p>Procedimento obrigatório para atividades potencialmente poluidoras.</p><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Licença</th><th style=''padding:10px;border:1px solid #ddd;''>Fase</th><th style=''padding:10px;border:1px solid #ddd;''>Objetivo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>LP (Prévia)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Planejamento</td><td style=''padding:10px;border:1px solid #ddd;''>Aprova localização e concepção</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>LI (Instalação)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Construção</td><td style=''padding:10px;border:1px solid #ddd;''>Autoriza instalação conforme projeto</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>LO (Operação)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Funcionamento</td><td style=''padding:10px;border:1px solid #ddd;''>Autoriza início das atividades</td></tr></table></div><h3>📊 Estudos Ambientais</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>EIA/RIMA</h4><ul><li><strong>EIA:</strong> Estudo de Impacto Ambiental (técnico)</li><li><strong>RIMA:</strong> Relatório (linguagem acessível)</li><li>Obrigatório para grandes empreendimentos</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>Outros Estudos</h4><ul><li><strong>RAP:</strong> Relatório Ambiental Preliminar</li><li><strong>PCA:</strong> Plano de Controle Ambiental</li><li><strong>RCA:</strong> Relatório de Controle Ambiental</li></ul></div></div><h3>🏛️ Órgãos Ambientais</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>IBAMA</strong><p>Federal</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>OEMA</strong><p>Estadual</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>Secretarias</strong><p>Municipal</p></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A ordem das licenças é sempre: <strong>LP → LI → LO</strong>. Não pode instalar sem LP, não pode operar sem LI!</p></div>'
WHERE titulo = 'Resumo: Gestão Ambiental';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=EJhWT9weRvI',
  conteudo_texto = '<h2>Legislação Ambiental</h2><p>Principais leis e normas ambientais brasileiras para concursos.</p><h3>📜 Constituição Federal (Art. 225)</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><p><em>"Todos têm direito ao meio ambiente ecologicamente equilibrado, bem de uso comum do povo e essencial à sadia qualidade de vida, impondo-se ao Poder Público e à coletividade o dever de defendê-lo e preservá-lo para as presentes e futuras gerações."</em></p></div><h3>📋 Principais Leis Ambientais</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Lei</th><th style=''padding:10px;border:1px solid #ddd;''>Assunto</th><th style=''padding:10px;border:1px solid #ddd;''>Pontos-chave</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Lei 6.938/81</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Política Nacional do Meio Ambiente</td><td style=''padding:10px;border:1px solid #ddd;''>SISNAMA, licenciamento, EIA</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Lei 9.605/98</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Crimes Ambientais</td><td style=''padding:10px;border:1px solid #ddd;''>Sanções penais e administrativas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Lei 12.651/12</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Código Florestal</td><td style=''padding:10px;border:1px solid #ddd;''>APP, Reserva Legal, CAR</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Lei 9.433/97</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Política de Recursos Hídricos</td><td style=''padding:10px;border:1px solid #ddd;''>Água é bem público, outorga</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Lei 12.305/10</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Política de Resíduos Sólidos</td><td style=''padding:10px;border:1px solid #ddd;''>Logística reversa, responsabilidade compartilhada</td></tr></table></div><h3>🏛️ SISNAMA</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p><strong>Sistema Nacional do Meio Ambiente</strong></p><table style=''width:100%;border-collapse:collapse;margin-top:10px;''><tr style=''background:#17a2b8;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Órgão</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>CONAMA</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Consultivo e deliberativo (resoluções)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>MMA</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Central (coordenação)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>IBAMA</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Executor federal</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Órgãos Estaduais</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Execução regional</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Órgãos Municipais</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Execução local</td></tr></table></div><h3>🌳 Código Florestal (Lei 12.651/12)</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#d4edda;padding:15px;border-radius:8px;''><h4>APP (Área de Preservação Permanente)</h4><ul><li>Margens de rios: 30-500m</li><li>Nascentes: 50m de raio</li><li>Topos de morros</li><li>Encostas > 45°</li><li><strong>Função:</strong> Preservar recursos hídricos</li></ul></div><div style=''flex:1;min-width:250px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Reserva Legal</h4><ul><li>Amazônia: 80%</li><li>Cerrado na Amazônia: 35%</li><li>Demais regiões: 20%</li><li><strong>Função:</strong> Uso sustentável</li></ul></div></div><h3>⚖️ Crimes Ambientais (Lei 9.605/98)</h3><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Fauna:</strong> Matar, caçar, apanhar animais silvestres</li><li><strong>Flora:</strong> Destruir, desmatar, incendiar</li><li><strong>Poluição:</strong> Causar danos à saúde humana ou ao ambiente</li><li><strong>Pessoa Jurídica:</strong> Empresa pode ser responsabilizada criminalmente</li></ul></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A <strong>Lei 6.938/81</strong> é a base de tudo: criou o SISNAMA, o licenciamento e o princípio do poluidor-pagador!</p></div>'
WHERE titulo = 'Resumo: Legislação Ambiental';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=6O6YP1J3Y8Y',
  conteudo_texto = '<h2>Poluição e Controle</h2><p>Tipos de poluição e medidas de controle ambiental.</p><h3>🏭 Tipos de Poluição</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#dc3545;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Fontes</th><th style=''padding:10px;border:1px solid #ddd;''>Impactos</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Atmosférica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indústrias, veículos, queimadas</td><td style=''padding:10px;border:1px solid #ddd;''>Efeito estufa, chuva ácida, smog</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Hídrica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Efluentes, esgoto, vazamentos</td><td style=''padding:10px;border:1px solid #ddd;''>Eutrofização, contaminação</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Solo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Resíduos, agrotóxicos, vazamentos</td><td style=''padding:10px;border:1px solid #ddd;''>Contaminação, erosão</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Sonora</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Máquinas, tráfego, construção</td><td style=''padding:10px;border:1px solid #ddd;''>Estresse, perda auditiva</td></tr></table></div><h3>💨 Poluentes Atmosféricos</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Poluente</th><th style=''padding:10px;border:1px solid #ddd;''>Fonte</th><th style=''padding:10px;border:1px solid #ddd;''>Efeito</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>CO₂</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Combustão</td><td style=''padding:10px;border:1px solid #ddd;''>Efeito estufa</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>SO₂</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Queima de combustíveis com enxofre</td><td style=''padding:10px;border:1px solid #ddd;''>Chuva ácida</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>NOx</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Combustão alta temperatura</td><td style=''padding:10px;border:1px solid #ddd;''>Smog, chuva ácida</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>MP (Material Particulado)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Indústrias, veículos diesel</td><td style=''padding:10px;border:1px solid #ddd;''>Doenças respiratórias</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>CH₄ (Metano)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Pecuária, aterros, petróleo</td><td style=''padding:10px;border:1px solid #ddd;''>Efeito estufa (21x CO₂)</td></tr></table></div><h3>🔧 Controle de Poluição Atmosférica</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Equipamentos</h4><ul><li><strong>Filtros:</strong> Manga, HEPA</li><li><strong>Ciclones:</strong> Partículas grossas</li><li><strong>Lavadores:</strong> Gases e partículas</li><li><strong>Precipitadores:</strong> Eletrostáticos</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Técnicas</h4><ul><li>Absorção</li><li>Adsorção</li><li>Combustão</li><li>Catalisadores</li></ul></div></div><h3>💧 Tratamento de Efluentes</h3><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#17a2b8;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Nível</th><th style=''padding:10px;border:1px solid #ddd;''>Processo</th><th style=''padding:10px;border:1px solid #ddd;''>Remove</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Preliminar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gradeamento, caixa de areia</td><td style=''padding:10px;border:1px solid #ddd;''>Sólidos grosseiros</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Primário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Decantação, flotação</td><td style=''padding:10px;border:1px solid #ddd;''>Sólidos sedimentáveis</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Secundário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lodos ativados, lagoas</td><td style=''padding:10px;border:1px solid #ddd;''>Matéria orgânica (DBO)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Terciário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Filtração, desinfecção</td><td style=''padding:10px;border:1px solid #ddd;''>Nutrientes, patógenos</td></tr></table></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p><strong>DBO</strong> (Demanda Bioquímica de Oxigênio) mede poluição orgânica. Quanto MAIOR a DBO, MAIS poluído o efluente!</p></div>'
WHERE titulo = 'Resumo: Poluição e Controle';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=gcJj5aw6BY8',
  conteudo_texto = '<h2>Sustentabilidade</h2><p>Desenvolvimento sustentável e ESG para concursos da Petrobras.</p><h3>🌍 Desenvolvimento Sustentável</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><p><em>"Desenvolvimento que atende às necessidades do presente sem comprometer a capacidade das futuras gerações de atender às suas próprias necessidades."</em></p><p style=''text-align:right;''><strong>— Relatório Brundtland, 1987</strong></p></div><h3>🔺 Tripé da Sustentabilidade</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#28a745;color:white;padding:15px;border-radius:8px;text-align:center;''><strong>🌱 Ambiental</strong><p>Preservação dos recursos naturais</p></div><div style=''flex:1;min-width:150px;background:#0066cc;color:white;padding:15px;border-radius:8px;text-align:center;''><strong>👥 Social</strong><p>Bem-estar e equidade</p></div><div style=''flex:1;min-width:150px;background:#ffc107;color:black;padding:15px;border-radius:8px;text-align:center;''><strong>💰 Econômico</strong><p>Viabilidade financeira</p></div></div><h3>📊 ESG</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#6f42c1;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Pilar</th><th style=''padding:10px;border:1px solid #ddd;''>Significado</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplos</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>E - Environmental</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Ambiental</td><td style=''padding:10px;border:1px solid #ddd;''>Emissões, energia, resíduos, água</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>S - Social</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Social</td><td style=''padding:10px;border:1px solid #ddd;''>Diversidade, segurança, comunidade</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>G - Governance</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Governança</td><td style=''padding:10px;border:1px solid #ddd;''>Ética, transparência, compliance</td></tr></table></div><h3>🎯 ODS - Objetivos de Desenvolvimento Sustentável</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>17 objetivos da ONU para 2030:</p><div style=''display:flex;flex-wrap:wrap;gap:8px;margin-top:10px;''><span style=''background:#e5243b;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>1. Erradicação da pobreza</span><span style=''background:#dda63a;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>2. Fome zero</span><span style=''background:#4c9f38;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>3. Saúde</span><span style=''background:#c5192d;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>4. Educação</span><span style=''background:#ff3a21;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>5. Igualdade de gênero</span><span style=''background:#26bde2;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>6. Água limpa</span><span style=''background:#fcc30b;color:black;padding:5px 10px;border-radius:15px;font-size:0.9em;''>7. Energia limpa</span><span style=''background:#a21942;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>8. Trabalho decente</span><span style=''background:#fd6925;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>9. Indústria e inovação</span><span style=''background:#0a97d9;color:white;padding:5px 10px;border-radius:15px;font-size:0.9em;''>13. Ação climática</span></div></div><h3>🌱 Economia Circular</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><h4>Linear → Circular</h4><p><strong>Linear:</strong> Extrair → Produzir → Usar → Descartar</p><p><strong>Circular:</strong> Reduzir → Reutilizar → Reciclar → Recuperar</p><h4>Princípios:</h4><ul><li>Eliminar resíduos e poluição</li><li>Manter produtos e materiais em uso</li><li>Regenerar sistemas naturais</li></ul></div><h3>🛢️ Petrobras e Sustentabilidade</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><ul><li><strong>Net Zero 2050:</strong> Meta de neutralidade de carbono</li><li><strong>Energias renováveis:</strong> Investimentos em eólica e solar</li><li><strong>Hidrogênio verde:</strong> Projetos de descarbonização</li><li><strong>CCUS:</strong> Captura e armazenamento de carbono</li></ul></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>ESG não é filantropia! É <strong>gestão de riscos e oportunidades</strong>. Empresas com bom ESG atraem mais investidores!</p></div>'
WHERE titulo = 'Resumo: Sustentabilidade';

UPDATE conteudos SET
  video_url = 'https://www.youtube.com/watch?v=cYX4t_BVQGU',
  conteudo_texto = '<h2>Emergências Ambientais</h2><p>Planos de contingência e resposta a acidentes ambientais.</p><h3>⚠️ Tipos de Emergências</h3><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#dc3545;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplos</th><th style=''padding:10px;border:1px solid #ddd;''>Impactos</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Vazamento de Óleo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Derramamento em mar/terra</td><td style=''padding:10px;border:1px solid #ddd;''>Fauna, flora, praias, pesca</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Incêndio/Explosão</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Refinarias, plataformas</td><td style=''padding:10px;border:1px solid #ddd;''>Poluição atmosférica, vítimas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Vazamento de Gás</strong></td><td style=''padding:10px;border:1px solid #ddd;''>H₂S, metano, CO</td><td style=''padding:10px;border:1px solid #ddd;''>Intoxicação, explosão</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Produtos Químicos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Ácidos, solventes</td><td style=''padding:10px;border:1px solid #ddd;''>Contaminação de solo e água</td></tr></table></div><h3>📋 Plano de Emergência Individual (PEI)</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Documento obrigatório pela Resolução CONAMA 398/2008 para:</p><ul><li>Plataformas de petróleo</li><li>Navios-tanque</li><li>Dutos</li><li>Terminais</li><li>Refinarias</li></ul><h4>Deve conter:</h4><ul><li>Análise de riscos</li><li>Procedimentos de resposta</li><li>Recursos disponíveis</li><li>Comunicação</li><li>Treinamentos</li></ul></div><h3>🔄 Fases da Resposta</h3><div style=''display:flex;gap:10px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:120px;background:#dc3545;color:white;padding:15px;border-radius:8px;text-align:center;''><strong>1. Alerta</strong><p>Detecção e comunicação</p></div><div style=''flex:1;min-width:120px;background:#ffc107;color:black;padding:15px;border-radius:8px;text-align:center;''><strong>2. Avaliação</strong><p>Análise da situação</p></div><div style=''flex:1;min-width:120px;background:#17a2b8;color:white;padding:15px;border-radius:8px;text-align:center;''><strong>3. Contenção</strong><p>Limitar o dano</p></div><div style=''flex:1;min-width:120px;background:#28a745;color:white;padding:15px;border-radius:8px;text-align:center;''><strong>4. Recuperação</strong><p>Limpeza e remediação</p></div></div><h3>🛢️ Resposta a Vazamento de Óleo</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Técnica</th><th style=''padding:10px;border:1px solid #ddd;''>Descrição</th><th style=''padding:10px;border:1px solid #ddd;''>Quando usar</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Barreiras de Contenção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Cercam a mancha</td><td style=''padding:10px;border:1px solid #ddd;''>Mar calmo, águas protegidas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Skimmers</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Recolhem óleo da superfície</td><td style=''padding:10px;border:1px solid #ddd;''>Manchas espessas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Absorventes</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Mantas, barreiras</td><td style=''padding:10px;border:1px solid #ddd;''>Pequenos volumes</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Dispersantes</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Quebram a mancha</td><td style=''padding:10px;border:1px solid #ddd;''>Mar aberto, autorização</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Biorremediação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Microrganismos degradam óleo</td><td style=''padding:10px;border:1px solid #ddd;''>Recuperação de áreas</td></tr></table></div><h3>📞 Cadeia de Comunicação</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><ol><li>Detecção → Comunicação interna</li><li>Acionamento da equipe de emergência</li><li>Notificação ao IBAMA (em até 24h)</li><li>Comunicação à ANP</li><li>Órgão estadual de meio ambiente</li><li>Defesa Civil (se necessário)</li></ol></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O <strong>PEI</strong> é obrigatório! A empresa deve notificar o IBAMA sobre vazamentos em até <strong>24 horas</strong> e iniciar resposta <strong>imediatamente</strong>!</p></div>'
WHERE titulo = 'Resumo: Emergências Ambientais';
